import { createLinterRuleTester, LinterRuleTester } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";
import { opInvariantCapRule } from "./op-invariant-cap.rule.js";

// Use letter-prefixed names so namespace-path / numeric-suffix rules don't fire.
const INV_NAMES = [
  "inv_a_one", "inv_b_two", "inv_c_three", "inv_d_four", "inv_e_five",
  "inv_f_six", "inv_g_seven", "inv_h_eight", "inv_i_nine", "inv_j_ten",
];

function makeInvariants(count: number): string {
  return INV_NAMES.slice(0, count)
    .map((n) => `@invariant(#{ predicate: "p", why: "r" }) op ${n}(): void;`)
    .join("\n          ");
}

function makeProjectsArgs(count: number): string {
  return INV_NAMES.slice(0, count)
    .map((n) => `Products.MyProduct.Features.Lifecycle.${n}`)
    .join(",\n            ");
}

const FEATURE = (count: number) => `
  @feature
  namespace Products.MyProduct.Features.Lifecycle {
    ${makeInvariants(count)}
  }
`;

// a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_op_invariant_cap
describe("op-invariant-cap rule", () => {
  let ruleTester: LinterRuleTester;

  beforeEach(async () => {
    const runner = await Tester.createInstance();
    ruleTester = createLinterRuleTester(runner, opInvariantCapRule, "@a10n/blueprint-typespec");
  });

  // ─── valid ────────────────────────────────────────────────────────────────

  describe("valid", () => {
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_op_invariant_cap
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T014.T014_01
    it("op projecting exactly 8 invariants passes", async () => {
      await ruleTester
        .expect(`
          ${FEATURE(8)}
          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            @tool(#{ sequential: false })
            @projects(${makeProjectsArgs(8)})
            op do_task(): void;
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T014.T014_02
    it("op without @projects is ignored", async () => {
      await ruleTester
        .expect(`
          ${FEATURE(8)}
          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            @tool(#{ sequential: false })
            op do_task(): void;
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T014.T014_05
    it("9 @projects args with a duplicate collapse to 8 distinct — passes the cap", async () => {
      // The cap counts DISTINCT invariant FQNs. Listing inv_a twice does not push past 8.
      // (The duplicate itself is flagged by invariant-projected-once-per-op, a separate rule.)
      await ruleTester
        .expect(`
          ${FEATURE(8)}
          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            // a10n:blueprint:ignore
            @tool(#{ sequential: false })
            @projects(
              ${makeProjectsArgs(8)},
              Products.MyProduct.Features.Lifecycle.inv_a_one
            )
            op do_task(): void;
          }
        `)
        .toBeValid();
    });
  });

  // ─── invalid ──────────────────────────────────────────────────────────────

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T014.T014_03
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_op_invariant_cap:Products.A10nBlueprintEngine.Features.InvariantProjection.op_invariant_cap:must
    it("op projecting 9 invariants emits warning", async () => {
      await ruleTester
        .expect(`
          ${FEATURE(9)}
          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            // a10n:blueprint:ignore
            @tool(#{ sequential: false })
            @projects(${makeProjectsArgs(9)})
            op do_task(): void;
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/op-invariant-cap",
          message: /9 invariants/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T014.T014_04
    it("message includes the operation FQN", async () => {
      await ruleTester
        .expect(`
          ${FEATURE(9)}
          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            // a10n:blueprint:ignore
            @tool(#{ sequential: false })
            @projects(${makeProjectsArgs(9)})
            op do_task(): void;
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/op-invariant-cap",
          message: /Components\.MyAgent\.do_task/,
        });
    });
  });
});
